import tarfile
import os

def extract_tar(tar_path, dest_dir):
    # Check if the tar file exists and is readable
    if not os.path.exists(tar_path) or not os.access(tar_path, os.R_OK):
        raise ValueError("Tar file does not exist or is not readable")
    
    # Check if the destination directory is writable
    if not os.access(dest_dir, os.W_OK):
        raise ValueError("Destination directory is not writable")
    
    # Extract the tar file to the destination directory
    with tarfile.open(tar_path) as tf:
        tf.extractall(dest_dir)